    /**
     * Получает АСП по номеру договора
     * @param string $number
     * @return false|int
     */
    public function getAspByContractNumber(string $number)
    {
        $sql = $this->db->placehold("SELECT asp, order_id FROM s_contracts WHERE number = ?", $number);
        $this->db->query($sql);
        $contract = $this->db->result();

        if (!($asp = $contract->asp)) {
            $asp = $this->orders->getAspByOrderId($contract->order_id);
        }

        return $asp;
    }

    /** Получаем сумму выдачи в определенной МКК за определенный период (s_contracts.status = 2 - выдача) */
    public function getIssuanceAmountForPeriod(string $dateStart, string $dateEnd, int $organizationId): int
    {
        $query = $this->db->placehold("
            SELECT SUM(amount) as issuance_amount
            FROM s_contracts
            WHERE organization_id = ?
                AND status = 2
                AND issuance_date >= ?
                AND issuance_date < ?
            ;
        ", $organizationId, $dateStart, $dateEnd);

        $this->db->query($query);
        return (int)$this->db->result('issuance_amount');
    }
